const fs = require('fs');
const path = require('path');
const data = JSON.parse(fs.readFileSync('data/tm_conversations_latest.json', 'utf8'));

const sysPatterns = [
  '自动接待将不再触发', 'Since you have read the conversation',
  'Marco大模型翻译', '阿里国际Marco大模型翻译',
  '买家有流失风险', 'Buyer has churn risk',
  '一旦离开平台发生纠纷或欺诈', '由于您介入该会话', 'Due to your intervention',
  '反馈', 'AI给您生成了一条回复建议',
  'You have a visitor. Follow up with them',
  'This buyer has been pre-screened',
  'Smart Assistant has determined',
  'Your business product has not been quoted',
];

function isSystemMsg(content) {
  if (!content) return true;
  for (const p of sysPatterns) {
    if (content.includes(p)) return true;
  }
  return false;
}

const CHAT_DIR = 'data/chat_history';
const chatFiles = fs.readdirSync(CHAT_DIR).filter(f => f.endsWith('.json'));

function cidToFile(cid) {
  const sanitized = cid.replace(/[<>:\"/|?*#@]/g, '_').substring(0, 200);
  for (const f of chatFiles) {
    if (f.includes(sanitized.substring(0, 30)) || sanitized.includes(f.replace('.json','').substring(0,30))) {
      return f;
    }
  }
  // Try matching by key numeric parts
  const parts = cid.split(/[#@\-]/);
  for (const f of chatFiles) {
    let match = 0;
    for (const p of parts) {
      if (p.length > 5 && f.includes(p)) match++;
    }
    if (match >= 2) return f;
  }
  return null;
}

// Build P0+P1 candidate list from conversations
const candidates = [];
const now = Date.now();
const DAY = 86400000;

for (const c of data.conversations) {
  const lm = c.latestMessage || {};
  const lmContent = typeof lm.content === 'string' ? lm.content : (lm.content?.text?.content || '');
  const lastTime = c.lastContactTime || 0;
  const daysSince = (now - lastTime) / DAY;
  const unread = c.unreadCount || 0;
  const isSys = isSystemMsg(lmContent);

  if (daysSince <= 7 && !isSys) {
    candidates.push({
      name: c.name,
      country: c.complianceCountryCode || '',
      cid: c.cid,
      daysSince: Math.round(daysSince),
      unread,
      lmContent: lmContent?.substring(0, 150),
      isCustomerMsg: lm.sendOrReceive === 0
    });
  }
}

console.log('候选池:', candidates.length, '人\n');

// Now extract key signals from each candidate's chat history
for (const cand of candidates) {
  const file = cidToFile(cand.cid);
  if (!file) {
    console.log(cand.name, '| 无chat文件');
    continue;
  }

  try {
    const chatData = JSON.parse(fs.readFileSync(path.join(CHAT_DIR, file), 'utf8'));
    const msgs = chatData.messages || [];

    // Filter out system messages and extract real conversation
    const realMsgs = [];
    for (const m of msgs) {
      const msg = m.message;
      const text = msg.content?.text?.content || '';
      if (!isSystemMsg(text) && text) {
        const sender = msg.sender?.uid || '';
        const isCustomer = !sender.includes('2500000853693'); // our ID
        realMsgs.push({
          text: text.substring(0, 200),
          isCustomer,
          time: msg.createAt ? new Date(msg.createAt).toISOString() : ''
        });
      }
    }

    // Last 3 customer messages
    const custMsgs = realMsgs.filter(m => m.isCustomer).slice(-3);
    const ourMsgs = realMsgs.filter(m => !m.isCustomer).slice(-3);

    // Upgrade signals
    const allText = realMsgs.map(m => m.text).join(' ');
    const signals = [];
    if (/place order|下单|make order|сделаем заказ/i.test(allText)) signals.push('下单信号');
    if (/address|地址|adresse|dirección|العنوان/.test(allText) && /\d{3,}/.test(allText)) signals.push('地址已给');
    if (/PI|proforma|invoice/.test(allText) && /send|sent|envoyé|发/.test(allText)) signals.push('PI已发');
    if (/partner|商量|discuss|brother|husband|wife|определюсь/.test(allText)) signals.push('需合伙商量');
    if (/sample|échantillon|muestra|образец|عينة/.test(allText)) signals.push('样品相关');
    if (/500|1000|MOQ|quantity|quantité|cantidad/.test(allText)) signals.push('数量讨论');

    // Insurance signals (downgrade)
    const downgrade = [];
    const lastCustMsg = custMsgs[custMsgs.length - 1];
    if (!lastCustMsg) {
      downgrade.push('无客户真实消息');
    } else {
      const lastCustDays = (now - new Date(lastCustMsg.time).getTime()) / DAY;
      if (lastCustDays > 5) downgrade.push('客户最后消息>' + Math.round(lastCustDays) + 'd');
    }
    if (/personal use|usage personnel|uso personal/.test(allText) && realMsgs.length < 8) downgrade.push('个人使用信号');

    console.log(cand.name, '|', cand.country, '|', realMsgs.length+'条有效', '|', custMsgs.length+'条客户');
    console.log('  信号:', signals.length > 0 ? signals.join(', ') : '无明显信号');
    if (downgrade.length > 0) console.log('  降级:', downgrade.join(', '));
    if (custMsgs.length > 0) {
      const last = custMsgs[custMsgs.length - 1];
      console.log('  客户最后:', last.text.substring(0, 200));
    }
    if (ourMsgs.length > 0) {
      const last = ourMsgs[ourMsgs.length - 1];
      console.log('  我方最后:', last.text.substring(0, 200));
    }
    console.log('');

  } catch(e) {
    console.log(cand.name, '| 读取错误:', e.message?.substring(0, 100));
  }
}
